function c(n,e){const i=e.filter(t=>t.type==="Priority"&&n.tagIds.includes(t.id));if(i.length===0)return 999;const r=i[0].name.toLowerCase();return r.includes("high")||r.includes("critical")||r.includes("urgent")||r.includes("hot")?1:r.includes("medium")||r.includes("warm")?2:r.includes("low")||r.includes("cold")?3:999}function u(n,e){return[...n].sort((i,o)=>{const r=c(i,e),t=c(o,e);return r!==t?r-t:i.createdAt-o.createdAt})}export{c as getPriorityLevel,u as sortTasksByPriority};
